/** Auto-generated soup reroll button arts — Granite `{ uri }`. */
export const SOUP_REROLL_IMAGE_URI = {
    common: 'data:image/png;base64,',
    hidden: 'data:image/png;base64,',
    legendary: 'data:image/png;base64,',
} as const;

export type SoupRerollImageKey = keyof typeof SOUP_REROLL_IMAGE_URI;

export function soupRerollUriSource(key: SoupRerollImageKey): { uri: string } {
    return { uri: SOUP_REROLL_IMAGE_URI[key] };
}
